#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007LL

long long modpow(long long a,long long e){
    long long r=1%MOD;
    while(e){
        if(e&1) r=r*a%MOD;
        a=a*a%MOD;
        e>>=1;
    }
    return r;
}

int main(){
    int N;
    if(scanf("%d",&N)!=1) return 0;
    int *cnt = (int*)calloc(100001,sizeof(int));
    for(int i=0;i<N;i++){
        int x,y; scanf("%d %d",&x,&y);
        cnt[x]++;
    }
    long long *fact = (long long*)malloc((N+1)*sizeof(long long));
    long long *invFact = (long long*)malloc((N+1)*sizeof(long long));
    fact[0]=1;
    for(int i=1;i<=N;i++) fact[i]=fact[i-1]*i%MOD;
    invFact[N]=modpow(fact[N],MOD-2);
    for(int i=N;i>0;i--) invFact[i-1]=invFact[i]*i%MOD;
    long long ans = invFact[N];
    for(int x=0;x<=100000;x++) if(cnt[x]) ans = ans * fact[cnt[x]] % MOD;
    printf("%lld\n",ans);
    free(cnt); free(fact); free(invFact);
    return 0;
}

