import sys
MOD = 1_000_000_007

def mod_pow(a, e):
    r = 1
    while e:
        if e & 1:
            r = r * a % MOD
        a = a * a % MOD
        e >>= 1
    return r

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    cnt = [0] * 100001
    for _ in range(N):
        x = int(next(it))
        y = int(next(it))  # y is unused
        cnt[x] += 1
    fact = [1] * (N + 1)
    for i in range(1, N + 1):
        fact[i] = fact[i - 1] * i % MOD
    inv_fact_N = mod_pow(fact[N], MOD - 2)
    ans = inv_fact_N
    for c in cnt:
        if c:
            ans = ans * fact[c] % MOD
    print(ans)

if __name__ == "__main__":
    main()

